//! Benchmarks for search indexing and query performance.
//!
//! Run with: cargo bench --bench search_bench

use std::time::Instant;
use uuid::Uuid;

use mneme_search::SearchEngine;

fn main() {
    let engine = SearchEngine::in_memory().unwrap();

    // --- Indexing throughput ---
    let note_count = 1000;
    let start = Instant::now();
    for i in 0..note_count {
        engine
            .index_note(
                Uuid::new_v4(),
                &format!("Note about topic {i}"),
                &format!(
                    "This is note number {i}. It contains content about various topics \
                     including programming, systems design, and knowledge management. \
                     The note discusses concepts related to topic {i} in detail.",
                ),
                &[format!("topic-{}", i % 10), format!("batch-{}", i / 100)],
                &format!("notes/topic-{i}.md"),
            )
            .unwrap();
    }
    let index_duration = start.elapsed();
    println!(
        "Indexed {} notes in {:.2}ms ({:.0} notes/sec)",
        note_count,
        index_duration.as_secs_f64() * 1000.0,
        note_count as f64 / index_duration.as_secs_f64()
    );

    // --- Search latency ---
    let queries = [
        "programming",
        "systems design",
        "knowledge management",
        "topic 42",
        "nonexistent term",
    ];

    let iterations = 100;
    for query in &queries {
        let start = Instant::now();
        for _ in 0..iterations {
            let _ = engine.search(query, 10).unwrap();
        }
        let duration = start.elapsed();
        let results = engine.search(query, 10).unwrap();
        println!(
            "Search '{}': {:.2}ms avg ({} results)",
            query,
            duration.as_secs_f64() * 1000.0 / iterations as f64,
            results.len()
        );
    }

    // --- Re-index (update) ---
    let update_id = Uuid::new_v4();
    engine
        .index_note(
            update_id,
            "Original Title",
            "Original content",
            &[],
            "update-test.md",
        )
        .unwrap();

    let start = Instant::now();
    for i in 0..100 {
        engine
            .index_note(
                update_id,
                &format!("Updated Title {i}"),
                &format!("Updated content {i}"),
                &[],
                "update-test.md",
            )
            .unwrap();
    }
    let update_duration = start.elapsed();
    println!(
        "Re-indexed 100 updates in {:.2}ms ({:.2}ms avg)",
        update_duration.as_secs_f64() * 1000.0,
        update_duration.as_secs_f64() * 10.0
    );
}

//! HTTP client for daimon Agent Runtime API.

use std::collections::HashMap;

use reqwest::Client;
use serde::{Deserialize, Serialize};

use crate::AiError;

/// Client for daimon's REST API (RAG, vectors, knowledge).
#[derive(Clone)]
pub struct DaimonClient {
    client: Client,
    base_url: String,
    api_key: Option<String>,
}

impl DaimonClient {
    /// Create a new client pointing to daimon.
    ///
    /// Defaults to `http://127.0.0.1:8090` if no URL provided.
    pub fn new(base_url: Option<String>, api_key: Option<String>) -> Self {
        Self {
            client: Client::new(),
            base_url: base_url.unwrap_or_else(|| "http://127.0.0.1:8090".into()),
            api_key,
        }
    }

    /// Check if daimon is reachable.
    pub async fn health_check(&self) -> Result<bool, AiError> {
        let resp = self
            .client
            .get(format!("{}/health", self.base_url))
            .send()
            .await;
        Ok(resp.is_ok_and(|r| r.status().is_success()))
    }

    // --- RAG ---

    /// Ingest text into the RAG pipeline.
    pub async fn rag_ingest(
        &self,
        text: &str,
        metadata: HashMap<String, String>,
    ) -> Result<RagIngestResponse, AiError> {
        let body = RagIngestRequest {
            text: text.to_string(),
            metadata,
            agent_id: Some("mneme".into()),
        };

        let resp = self
            .request_post("/v1/rag/ingest", &body)
            .await?
            .json::<RagIngestResponse>()
            .await?;
        Ok(resp)
    }

    /// Query the RAG pipeline.
    pub async fn rag_query(
        &self,
        query: &str,
        top_k: Option<usize>,
    ) -> Result<RagQueryResponse, AiError> {
        let body = RagQueryRequest {
            query: query.to_string(),
            top_k: top_k.unwrap_or(5),
        };

        let resp = self
            .request_post("/v1/rag/query", &body)
            .await?
            .json::<RagQueryResponse>()
            .await?;
        Ok(resp)
    }

    /// Get RAG pipeline stats.
    pub async fn rag_stats(&self) -> Result<RagStatsResponse, AiError> {
        let resp = self
            .request_get("/v1/rag/stats")
            .await?
            .json::<RagStatsResponse>()
            .await?;
        Ok(resp)
    }

    // --- Vectors ---

    /// Insert vectors into a collection.
    pub async fn vectors_insert(
        &self,
        collection: &str,
        vectors: Vec<VectorInsertItem>,
    ) -> Result<VectorInsertResponse, AiError> {
        let body = VectorInsertRequest {
            collection: collection.to_string(),
            vectors,
        };

        let resp = self
            .request_post("/v1/vectors/insert", &body)
            .await?
            .json::<VectorInsertResponse>()
            .await?;
        Ok(resp)
    }

    /// Search vectors by embedding similarity.
    pub async fn vectors_search(
        &self,
        embedding: Vec<f32>,
        collection: &str,
        top_k: usize,
    ) -> Result<VectorSearchResponse, AiError> {
        let body = VectorSearchRequest {
            embedding,
            top_k,
            collection: collection.to_string(),
            min_score: None,
        };

        let resp = self
            .request_post("/v1/vectors/search", &body)
            .await?
            .json::<VectorSearchResponse>()
            .await?;
        Ok(resp)
    }

    // --- Knowledge ---

    /// Search the knowledge base.
    pub async fn knowledge_search(
        &self,
        query: &str,
        limit: Option<usize>,
    ) -> Result<KnowledgeSearchResponse, AiError> {
        let body = KnowledgeSearchRequest {
            query: query.to_string(),
            source: None,
            limit: limit.unwrap_or(10),
        };

        let resp = self
            .request_post("/v1/knowledge/search", &body)
            .await?
            .json::<KnowledgeSearchResponse>()
            .await?;
        Ok(resp)
    }

    // --- HTTP helpers ---

    async fn request_post<T: Serialize>(
        &self,
        path: &str,
        body: &T,
    ) -> Result<reqwest::Response, AiError> {
        let url = format!("{}{}", self.base_url, path);
        let mut req = self.client.post(&url).json(body);
        if let Some(key) = &self.api_key {
            req = req.bearer_auth(key);
        }
        let resp = req.send().await.map_err(|e| AiError::Unavailable {
            url: url.clone(),
            reason: e.to_string(),
        })?;
        if !resp.status().is_success() {
            let status = resp.status();
            let body = resp.text().await.unwrap_or_default();
            return Err(AiError::Daimon(format!("{status}: {body}")));
        }
        Ok(resp)
    }

    async fn request_get(&self, path: &str) -> Result<reqwest::Response, AiError> {
        let url = format!("{}{}", self.base_url, path);
        let mut req = self.client.get(&url);
        if let Some(key) = &self.api_key {
            req = req.bearer_auth(key);
        }
        let resp = req.send().await.map_err(|e| AiError::Unavailable {
            url: url.clone(),
            reason: e.to_string(),
        })?;
        if !resp.status().is_success() {
            let status = resp.status();
            let body = resp.text().await.unwrap_or_default();
            return Err(AiError::Daimon(format!("{status}: {body}")));
        }
        Ok(resp)
    }
}

