        let suggestions = suggest_tags(content, &existing, 5).unwrap();
        assert!(!suggestions.is_empty());
        // Should suggest topic-level concepts
        assert!(suggestions.iter().all(|s| matches!(s.reason, TagReason::ConceptMatch)));
    }

