            },
            CalendarEntry {
                date: NaiveDate::from_ymd_opt(2026, 3, 15).unwrap(),
                note_id: Uuid::new_v4(),
                title: "March 15".into(),
                entry_type: EntryType::Event,
            },
            CalendarEntry {
                date: NaiveDate::from_ymd_opt(2026, 4, 1).unwrap(),
