    }
}

//! Mneme MCP — Model Context Protocol server.
//!
//! Stdio-based JSON-RPC 2.0 server exposing 5 tools for Claude integration:
//! - `mneme_create_note` — create a new note
//! - `mneme_search` — search notes
//! - `mneme_get_note` — retrieve a note
//! - `mneme_update_note` — update a note
//! - `mneme_query_graph` — query the knowledge graph

pub mod protocol;
pub mod tools;

//! Mneme MCP server entry point — stdio JSON-RPC 2.0.

use std::path::PathBuf;
use std::sync::Arc;

use anyhow::Result;
use serde_json::{Value, json};
use tokio::io::{self, AsyncBufReadExt, AsyncWriteExt, BufReader};

use mneme_mcp::protocol::{jsonrpc_error, tool_definitions};
use mneme_mcp::tools::handle_tool_call;
use mneme_search::SearchEngine;
use mneme_store::Vault;

#[tokio::main]
async fn main() -> Result<()> {
    tracing_subscriber::fmt()
        .with_env_filter("mneme_mcp=debug")
        .with_writer(std::io::stderr)
        .init();

    tracing::info!("mneme-mcp server starting (stdio)");

    let vault_dir = std::env::var("MNEME_VAULT_DIR")
        .map(PathBuf::from)
        .unwrap_or_else(|_| {
            dirs::home_dir()
                .unwrap_or_else(|| PathBuf::from("."))
                .join("mneme")
        });

    let vault = Vault::open(&vault_dir).await?;
    let search_dir = vault_dir.join(".mneme").join("search-index");
    let search = SearchEngine::open(&search_dir)?;

    let vault = Arc::new(vault);
    let search = Arc::new(search);

    let stdin = io::stdin();
    let mut stdout = io::stdout();
    let mut reader = BufReader::new(stdin);
    let mut line = String::new();

    loop {
        line.clear();
        let n = reader.read_line(&mut line).await?;
        if n == 0 {
            break;
        }

        let request: Value = match serde_json::from_str(line.trim()) {
            Ok(v) => v,
            Err(e) => {
                tracing::warn!("invalid JSON: {e}");
                continue;
            }
        };

        let response = handle_request(&request, &vault, &search).await;
        let mut out = serde_json::to_string(&response)?;
        out.push('\n');
        stdout.write_all(out.as_bytes()).await?;
        stdout.flush().await?;
    }

    Ok(())
}

async fn handle_request(request: &Value, vault: &Vault, search: &SearchEngine) -> Value {
    let method = request.get("method").and_then(|m| m.as_str()).unwrap_or("");
    let id = request.get("id").cloned().unwrap_or(Value::Null);

    match method {
        "initialize" => json!({
            "jsonrpc": "2.0",
            "id": id,
            "result": {
                "protocolVersion": "2024-11-05",
                "serverInfo": {
                    "name": "mneme-mcp",
                    "version": env!("CARGO_PKG_VERSION"),
                },
                "capabilities": {
                    "tools": {}
                }
            }
        }),
        "tools/list" => json!({
            "jsonrpc": "2.0",
            "id": id,
            "result": {
                "tools": tool_definitions()
            }
        }),
        "tools/call" => {
            let params = request.get("params").cloned().unwrap_or(json!({}));
            let tool_name = params.get("name").and_then(|n| n.as_str()).unwrap_or("");
            let args = params.get("arguments").cloned().unwrap_or(json!({}));
            handle_tool_call(&id, tool_name, &args, vault, search).await
        }
        _ => jsonrpc_error(&id, -32601, format!("unknown method: {method}")),
    }
}

//! MCP JSON-RPC 2.0 protocol helpers.

use serde_json::{Value, json};

/// Build a successful MCP tool result.
pub fn mcp_success(id: &Value, text: impl Into<String>) -> Value {
    json!({
        "jsonrpc": "2.0",
        "id": id,
        "result": {
            "content": [{
                "type": "text",
                "text": text.into()
            }]
        }
    })
}

/// Build an error MCP tool result.
pub fn mcp_error(id: &Value, msg: impl Into<String>) -> Value {
    json!({
        "jsonrpc": "2.0",
        "id": id,
        "result": {
            "content": [{
                "type": "text",
                "text": msg.into()
            }],
            "isError": true
        }
    })
}

/// Build a JSON-RPC error (protocol-level, not tool-level).
pub fn jsonrpc_error(id: &Value, code: i32, message: impl Into<String>) -> Value {
    json!({
        "jsonrpc": "2.0",
        "id": id,
        "error": {
            "code": code,
            "message": message.into()
        }
    })
}

/// Tool schema definitions for `tools/list`.
pub fn tool_definitions() -> Value {
    json!([
        {
            "name": "mneme_create_note",
            "description": "Create a new note in the Mneme knowledge base with title, content, and optional tags",
            "inputSchema": {
                "type": "object",
                "properties": {
                    "title": { "type": "string", "description": "Note title" },
                    "content": { "type": "string", "description": "Markdown content" },
                    "tags": {
                        "type": "array",
                        "items": { "type": "string" },
                        "description": "Tags to apply (e.g. [\"rust\", \"project/agnos\"])"
                    },
                    "path": { "type": "string", "description": "Optional file path relative to vault (auto-generated from title if omitted)" }
                },
                "required": ["title", "content"]
            }
        },
        {
            "name": "mneme_search",
            "description": "Search notes by keyword, full-text query, or tag filter",
            "inputSchema": {
                "type": "object",
                "properties": {
                    "query": { "type": "string", "description": "Search query" },
                    "limit": { "type": "integer", "description": "Max results (default: 10)", "default": 10 }
                },
                "required": ["query"]
            }
        },
        {
            "name": "mneme_get_note",
            "description": "Retrieve a note by ID with its full content, tags, and backlinks",
            "inputSchema": {
                "type": "object",
                "properties": {
                    "id": { "type": "string", "description": "Note UUID" }
                },
                "required": ["id"]
            }
        },
        {
            "name": "mneme_update_note",
            "description": "Update a note's title, content, or tags",
            "inputSchema": {
                "type": "object",
                "properties": {
                    "id": { "type": "string", "description": "Note UUID" },
                    "title": { "type": "string", "description": "New title (optional)" },
                    "content": { "type": "string", "description": "New markdown content (optional)" },
                    "tags": {
                        "type": "array",
                        "items": { "type": "string" },
                        "description": "Replace tags (optional)"
                    }
                },
                "required": ["id"]
            }
        },
        {
            "name": "mneme_query_graph",
            "description": "Query the knowledge graph for notes related to a given note, tag, or concept",
            "inputSchema": {
                "type": "object",
                "properties": {
                    "note_id": { "type": "string", "description": "Center node UUID (optional)" },
                    "tag": { "type": "string", "description": "Filter by tag name (optional)" },
                    "depth": { "type": "integer", "description": "Traversal depth (default: 1)", "default": 1 }
                }
            }
        }
    ])
}

