        assert_eq!(title_to_path("What's New? (2026)"), "what-s-new-2026.md");
    }

    #[test]
    fn title_to_path_collapses_hyphens() {
        assert_eq!(title_to_path("a   b"), "a-b.md");
    }
}

//! Mneme Store — persistence layer.
//!
//! Manages SQLite database for note metadata, tags, and links.
//! Note content is stored as plain Markdown files on disk.

pub mod db;
pub mod error;
pub mod files;
pub mod sharing;
pub mod vault;
pub mod versioning;

pub use error::StoreError;
pub use vault::Vault;

//! Vault sharing — multi-user access and conflict resolution.
//!
//! Tracks vault sharing state, user permissions, and provides
//! conflict detection for concurrent edits.

use chrono::{DateTime, Utc};
use serde::{Deserialize, Serialize};
use uuid::Uuid;

/// A user with access to a shared vault.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct VaultUser {
    pub id: Uuid,
    pub name: String,
    pub role: UserRole,
    pub joined_at: DateTime<Utc>,
    pub last_active: DateTime<Utc>,
}

/// User permission level.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum UserRole {
    Owner,
    Editor,
    Viewer,
}

impl UserRole {
    pub fn can_edit(&self) -> bool {
        matches!(self, UserRole::Owner | UserRole::Editor)
    }

    pub fn can_manage(&self) -> bool {
        matches!(self, UserRole::Owner)
    }
}

/// Sharing configuration for a vault.
#[derive(Debug, Clone, Default, Serialize, Deserialize)]
pub struct SharingConfig {
    pub enabled: bool,
    pub users: Vec<VaultUser>,
    pub allow_anonymous_read: bool,
}

impl SharingConfig {
    pub fn new() -> Self {
        Self::default()
    }

    /// Enable sharing for this vault.
    pub fn enable(&mut self) {
        self.enabled = true;
    }

    /// Add a user to the vault.
    pub fn add_user(&mut self, name: &str, role: UserRole) -> VaultUser {
        let now = Utc::now();
        let user = VaultUser {
            id: Uuid::new_v4(),
            name: name.to_string(),
            role,
            joined_at: now,
            last_active: now,
        };
        self.users.push(user.clone());
        user
    }

    /// Remove a user by ID.
    pub fn remove_user(&mut self, user_id: Uuid) -> bool {
        let before = self.users.len();
        self.users.retain(|u| u.id != user_id);
        self.users.len() < before
    }

    /// Get a user by ID.
    pub fn get_user(&self, user_id: Uuid) -> Option<&VaultUser> {
        self.users.iter().find(|u| u.id == user_id)
    }

    /// Check if a user can edit.
    pub fn can_edit(&self, user_id: Uuid) -> bool {
        self.users
            .iter()
            .any(|u| u.id == user_id && u.role.can_edit())
    }

    /// List all editors and owner.
    pub fn editors(&self) -> Vec<&VaultUser> {
        self.users.iter().filter(|u| u.role.can_edit()).collect()
    }
}

/// A conflict detected during concurrent edits.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct EditConflict {
    pub note_id: Uuid,
    pub user_a: String,
    pub user_b: String,
    pub base_hash: String,
    pub hash_a: String,
    pub hash_b: String,
    pub detected_at: DateTime<Utc>,
}

/// Conflict resolution strategy.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum ConflictStrategy {
    /// Last write wins
    LastWrite,
    /// Keep both versions (create a conflict note)
    KeepBoth,
    /// Manual resolution required
    Manual,
}

/// Detect a conflict between two edits.
pub fn detect_conflict(
    note_id: Uuid,
    base_hash: &str,
    edit_a: (&str, &str), // (user_name, new_hash)
    edit_b: (&str, &str),
) -> Option<EditConflict> {
    if edit_a.1 != edit_b.1 {
        Some(EditConflict {
            note_id,
            user_a: edit_a.0.to_string(),
            user_b: edit_b.0.to_string(),
            base_hash: base_hash.to_string(),
            hash_a: edit_a.1.to_string(),
            hash_b: edit_b.1.to_string(),
            detected_at: Utc::now(),
        })
    } else {
        None // Same result, no conflict
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn add_and_list_users() {
        let mut config = SharingConfig::new();
        config.enable();
        config.add_user("Alice", UserRole::Owner);
        config.add_user("Bob", UserRole::Editor);
        config.add_user("Charlie", UserRole::Viewer);

        assert!(config.enabled);
        assert_eq!(config.users.len(), 3);
        assert_eq!(config.editors().len(), 2); // Alice + Bob
    }

    #[test]
    fn remove_user() {
        let mut config = SharingConfig::new();
        let user = config.add_user("Alice", UserRole::Editor);
        assert!(config.remove_user(user.id));
        assert!(!config.remove_user(Uuid::new_v4())); // nonexistent
    }

    #[test]
    fn role_permissions() {
        assert!(UserRole::Owner.can_edit());
        assert!(UserRole::Owner.can_manage());
        assert!(UserRole::Editor.can_edit());
        assert!(!UserRole::Editor.can_manage());
        assert!(!UserRole::Viewer.can_edit());
        assert!(!UserRole::Viewer.can_manage());
    }

    #[test]
    fn can_edit_check() {
        let mut config = SharingConfig::new();
        let editor = config.add_user("Editor", UserRole::Editor);
        let viewer = config.add_user("Viewer", UserRole::Viewer);

        assert!(config.can_edit(editor.id));
        assert!(!config.can_edit(viewer.id));
        assert!(!config.can_edit(Uuid::new_v4()));
    }

    #[test]
    fn detect_conflict_different_hashes() {
        let note_id = Uuid::new_v4();
        let conflict = detect_conflict(note_id, "base", ("Alice", "hash_a"), ("Bob", "hash_b"));
        assert!(conflict.is_some());
        let c = conflict.unwrap();
        assert_eq!(c.user_a, "Alice");
        assert_eq!(c.user_b, "Bob");
    }

    #[test]
    fn no_conflict_same_hash() {
        let note_id = Uuid::new_v4();
        let conflict = detect_conflict(note_id, "base", ("Alice", "same"), ("Bob", "same"));
        assert!(conflict.is_none());
    }

    #[test]
    fn sharing_serialization() {
        let mut config = SharingConfig::new();
        config.enable();
        config.add_user("Test", UserRole::Editor);
        let json = serde_json::to_string(&config).unwrap();
        assert!(json.contains("editor"));
    }
}

//! Vault — the top-level store combining DB and file operations.

use std::path::{Path, PathBuf};
use uuid::Uuid;

use mneme_core::frontmatter::{
    Frontmatter, compose_document, parse_frontmatter, split_frontmatter,
};
use mneme_core::note::{CreateNote, Note, NoteWithContent, UpdateNote};
use mneme_core::tag::Tag;

use crate::StoreError;
use crate::db::Database;
use crate::files::{FileStore, content_hash, title_to_path};

/// A vault encapsulates a notes directory + SQLite database.
pub struct Vault {
    db: Database,
    files: FileStore,
    root: PathBuf,
}

impl Vault {
    /// Open a vault at the given directory path.
    pub async fn open(root: &Path) -> Result<Self, StoreError> {
        let db_path = root.join(".mneme").join("db.sqlite");
        tokio::fs::create_dir_all(root.join(".mneme")).await?;

        let db = Database::open(db_path.to_str().unwrap()).await?;
        let files = FileStore::new(root);
        files.init().await?;

        Ok(Self {
            db,
            files,
            root: root.to_path_buf(),
        })
    }

    pub fn root(&self) -> &Path {
        &self.root
    }

    pub fn db(&self) -> &Database {
        &self.db
    }

    // --- Note operations ---

    /// Create a new note.
    pub async fn create_note(&self, req: CreateNote) -> Result<NoteWithContent, StoreError> {
        let path = req.path.unwrap_or_else(|| title_to_path(&req.title));

        // Check for path conflict
        if self.files.exists(&path).await {
            return Err(StoreError::PathConflict(path));
        }

        // Build frontmatter
        let fm = Frontmatter {
            title: Some(req.title.clone()),
            tags: req.tags.clone(),
            ..Default::default()
        };
        let document = compose_document(&fm, &req.content);
        let hash = content_hash(&document);

        // Write file
        self.files.write_note(&path, &document).await?;

        // Create DB record
        let note = Note::new(req.title, path, hash);
        self.db.insert_note(&note).await?;

        // Create tags and associations
        for tag_name in &req.tags {
            let tag = self.db.get_or_create_tag(tag_name).await?;
            self.db.tag_note(note.id, tag.id).await?;
        }

        Ok(NoteWithContent {
            note,
            content: req.content,
            tags: req.tags,
            backlinks: vec![],
        })
    }

    /// Get a note with its full content.
    pub async fn get_note(&self, id: Uuid) -> Result<NoteWithContent, StoreError> {
        let note = self.db.get_note(id).await?;
        let document = self.files.read_note(&note.path).await?;
        let (yaml, body) = split_frontmatter(&document);

        let tags = self.db.get_note_tags(note.id).await?;
        let backlinks = self.db.get_backlinks(note.id).await?;

        let fm = yaml.map(parse_frontmatter);
        let _ = fm; // frontmatter already reflected in DB

        Ok(NoteWithContent {
            note,
            content: body.to_string(),
            tags,
            backlinks,
        })
    }

    /// List notes with pagination.
    pub async fn list_notes(&self, limit: i64, offset: i64) -> Result<Vec<Note>, StoreError> {
        self.db.list_notes(limit, offset).await
    }

    /// Update a note's content and/or title.
    pub async fn update_note(
        &self,
        id: Uuid,
        req: UpdateNote,
    ) -> Result<NoteWithContent, StoreError> {
        let note = self.db.get_note(id).await?;
        let document = self.files.read_note(&note.path).await?;
        let (yaml, body) = split_frontmatter(&document);

        let mut fm = yaml.map(parse_frontmatter).unwrap_or_default();

        let new_title = req.title.unwrap_or(note.title.clone());
        let new_content = req.content.unwrap_or_else(|| body.to_string());

        fm.title = Some(new_title.clone());

        // Update tags if provided
        if let Some(new_tags) = &req.tags {
            fm.tags = new_tags.clone();
            self.db.clear_note_tags(id).await?;
            for tag_name in new_tags {
                let tag = self.db.get_or_create_tag(tag_name).await?;
                self.db.tag_note(id, tag.id).await?;
            }
        }

        let new_document = compose_document(&fm, &new_content);
        let hash = content_hash(&new_document);

        self.files.write_note(&note.path, &new_document).await?;
        self.db.update_note(id, &new_title, &hash).await?;

        let tags = self.db.get_note_tags(id).await?;
        let backlinks = self.db.get_backlinks(id).await?;

        Ok(NoteWithContent {
            note: Note {
                title: new_title,
                content_hash: hash,
                ..note
            },
            content: new_content,
            tags,
            backlinks,
        })
    }

    /// Delete a note from both DB and filesystem.
    pub async fn delete_note(&self, id: Uuid) -> Result<(), StoreError> {
        let note = self.db.get_note(id).await?;
        self.db.delete_note(id).await?;
        // File deletion is best-effort
        let _ = self.files.delete_note(&note.path).await;
        Ok(())
    }

    /// Count total notes in the vault.
    pub async fn count_notes(&self) -> Result<i64, StoreError> {
        self.db.count_notes().await
    }

    // --- Tag operations ---

    /// List all tags.
    pub async fn list_tags(&self) -> Result<Vec<Tag>, StoreError> {
        self.db.list_tags().await
    }

    /// Delete a tag.
    pub async fn delete_tag(&self, id: Uuid) -> Result<(), StoreError> {
        self.db.delete_tag(id).await
    }
}

