        let (mut app, _dir) = test_app().await;
        app.panel = Panel::NoteView;
        app.selected_index = 0;
        app.select_next();
        assert_eq!(app.selected_index, 0); // no-op in NoteView
    }
}

//! Mneme UI — terminal user interface.
//!
//! Provides a TUI with:
//! - Note list with search
//! - Markdown note viewer
//! - Backlinks panel
//! - Tag browser
//! - Keyboard-driven navigation

pub mod app;
pub mod views;

//! Mneme TUI entry point.

use std::path::PathBuf;

use anyhow::Result;
use crossterm::ExecutableCommand;
use crossterm::event::{self, Event, KeyCode, KeyEventKind};
use crossterm::terminal::{
    EnterAlternateScreen, LeaveAlternateScreen, disable_raw_mode, enable_raw_mode,
};
use ratatui::Terminal;
use ratatui::backend::CrosstermBackend;

use mneme_search::SearchEngine;
use mneme_store::Vault;
use mneme_ui::app::{App, Panel};
use mneme_ui::views;

#[tokio::main]
async fn main() -> Result<()> {
    let vault_dir = std::env::var("MNEME_VAULT_DIR")
        .map(PathBuf::from)
        .unwrap_or_else(|_| {
            dirs::home_dir()
                .unwrap_or_else(|| PathBuf::from("."))
                .join("mneme")
        });

    let vault = Vault::open(&vault_dir).await?;
    let search_dir = vault_dir.join(".mneme").join("search-index");
    let search = SearchEngine::open(&search_dir)?;

    let mut app = App::new(vault, search);
    app.load_notes().await;
    app.load_tags().await;

    // Terminal setup
    enable_raw_mode()?;
    std::io::stdout().execute(EnterAlternateScreen)?;
    let backend = CrosstermBackend::new(std::io::stdout());
    let mut terminal = Terminal::new(backend)?;

    // Main loop
    loop {
        terminal.draw(|frame| views::render(frame, &app))?;

        if let Event::Key(key) = event::read()? {
            if key.kind != KeyEventKind::Press {
                continue;
            }

            match app.panel {
                Panel::Search => match key.code {
                    KeyCode::Esc => {
                        app.panel = Panel::NoteList;
                        app.selected_index = 0;
                    }
                    KeyCode::Char(c) => {
                        app.search_query.push(c);
                        app.run_search();
                    }
                    KeyCode::Backspace => {
                        app.search_query.pop();
                        app.run_search();
                    }
                    KeyCode::Enter => {
                        if let Some((_id, _, _)) =
                            app.search_results.get(app.selected_index).cloned()
                        {
                            let id = _id;
                            app.select_note(id).await;
                        }
                    }
                    KeyCode::Up => app.select_prev(),
                    KeyCode::Down => app.select_next(),
                    _ => {}
                },
                _ => match key.code {
                    KeyCode::Char('q') => {
                        app.should_quit = true;
                    }
                    KeyCode::Char('/') => {
                        app.panel = Panel::Search;
                        app.search_query.clear();
                        app.search_results.clear();
                        app.selected_index = 0;
                    }
                    KeyCode::Char('n') => {
                        app.panel = Panel::NoteList;
                        app.selected_index = 0;
                        app.load_notes().await;
                    }
                    KeyCode::Char('t') => {
                        app.panel = Panel::Tags;
                        app.selected_index = 0;
                        app.load_tags().await;
                    }
                    KeyCode::Esc => {
                        if app.panel == Panel::NoteView {
                            app.panel = Panel::NoteList;
                        }
                    }
                    KeyCode::Up | KeyCode::Char('k') => app.select_prev(),
                    KeyCode::Down | KeyCode::Char('j') => app.select_next(),
                    KeyCode::Enter => {
                        if app.panel == Panel::NoteList
                            && let Some(note) = app.notes.get(app.selected_index).cloned()
                        {
                            app.select_note(note.id).await;
                        }
                    }
                    _ => {}
                },
            }
        }

        if app.should_quit {
            break;
        }
    }

    // Cleanup
    disable_raw_mode()?;
    std::io::stdout().execute(LeaveAlternateScreen)?;

    Ok(())
}

//! TUI view rendering with ratatui.

use ratatui::Frame;
use ratatui::layout::{Constraint, Direction, Layout};
use ratatui::style::{Color, Modifier, Style};
use ratatui::text::{Line, Span};
use ratatui::widgets::{Block, Borders, List, ListItem, Paragraph, Wrap};

use crate::app::{App, Panel};

/// Render the full TUI layout.
pub fn render(frame: &mut Frame, app: &App) {
    let chunks = Layout::default()
        .direction(Direction::Vertical)
        .constraints([
            Constraint::Min(3),    // Main content
            Constraint::Length(1), // Status bar
        ])
        .split(frame.area());

    match app.panel {
        Panel::NoteList => render_note_list(frame, app, chunks[0]),
        Panel::NoteView => render_note_view(frame, app, chunks[0]),
        Panel::Search => render_search(frame, app, chunks[0]),
        Panel::Tags => render_tags(frame, app, chunks[0]),
    }

    // Status bar
    let status = Paragraph::new(Line::from(vec![
        Span::styled(
            format!(" {} ", panel_name(app.panel)),
            Style::default()
                .fg(Color::Black)
                .bg(Color::Cyan)
                .add_modifier(Modifier::BOLD),
        ),
        Span::raw(" "),
        Span::raw(&app.status_message),
        Span::raw("  "),
        Span::styled(
            "[q]uit [/]search [n]otes [t]ags [?]help",
            Style::default().fg(Color::DarkGray),
        ),
    ]));
    frame.render_widget(status, chunks[1]);
}

fn render_note_list(frame: &mut Frame, app: &App, area: ratatui::layout::Rect) {
    let items: Vec<ListItem> = app
        .notes
        .iter()
        .enumerate()
        .map(|(i, note)| {
            let style = if i == app.selected_index {
                Style::default()
                    .fg(Color::Yellow)
                    .add_modifier(Modifier::BOLD)
            } else {
                Style::default()
            };
            let date = note.updated_at.format("%m/%d");
            ListItem::new(Line::from(vec![
                Span::styled(format!("{date}  "), Style::default().fg(Color::DarkGray)),
                Span::styled(&note.title, style),
            ]))
        })
        .collect();

    let list = List::new(items).block(
        Block::default()
            .borders(Borders::ALL)
            .title(format!(" Notes ({}) ", app.notes.len())),
    );

    frame.render_widget(list, area);
}

fn render_note_view(frame: &mut Frame, app: &App, area: ratatui::layout::Rect) {
    let chunks = Layout::default()
        .direction(Direction::Horizontal)
        .constraints([
            Constraint::Percentage(75), // Note content
            Constraint::Percentage(25), // Sidebar (tags + backlinks)
        ])
        .split(area);

    // Note content
    let content = Paragraph::new(app.note_content.as_str())
        .wrap(Wrap { trim: false })
        .block(
            Block::default()
                .borders(Borders::ALL)
                .title(" Note ")
                .border_style(Style::default().fg(Color::Cyan)),
        );
    frame.render_widget(content, chunks[0]);

    // Sidebar
    let sidebar_chunks = Layout::default()
        .direction(Direction::Vertical)
        .constraints([
            Constraint::Percentage(40), // Tags
            Constraint::Percentage(60), // Backlinks
        ])
        .split(chunks[1]);

    // Tags
    let tag_items: Vec<ListItem> = app
        .note_tags
        .iter()
        .map(|t| {
            ListItem::new(Span::styled(
                format!("  #{t}"),
                Style::default().fg(Color::Green),
            ))
        })
        .collect();
    let tags_list = List::new(tag_items).block(
        Block::default()
            .borders(Borders::ALL)
            .title(format!(" Tags ({}) ", app.note_tags.len())),
    );
    frame.render_widget(tags_list, sidebar_chunks[0]);

    // Backlinks
    let bl_items: Vec<ListItem> = app
        .note_backlinks
        .iter()
        .map(|(title, _id)| {
            ListItem::new(Span::styled(
                format!("  ← {title}"),
                Style::default().fg(Color::Magenta),
            ))
        })
        .collect();
    let bl_list = List::new(bl_items).block(
        Block::default()
            .borders(Borders::ALL)
            .title(format!(" Backlinks ({}) ", app.note_backlinks.len())),
    );
    frame.render_widget(bl_list, sidebar_chunks[1]);
}

fn render_search(frame: &mut Frame, app: &App, area: ratatui::layout::Rect) {
    let chunks = Layout::default()
        .direction(Direction::Vertical)
        .constraints([
            Constraint::Length(3), // Search input
            Constraint::Min(1),    // Results
        ])
        .split(area);

    // Search input
    let input = Paragraph::new(format!("  {}", app.search_query)).block(
        Block::default()
            .borders(Borders::ALL)
            .title(" Search ")
            .border_style(Style::default().fg(Color::Yellow)),
    );
    frame.render_widget(input, chunks[0]);

    // Results
    let items: Vec<ListItem> = app
        .search_results
        .iter()
        .enumerate()
        .map(|(i, (_id, title, score))| {
            let style = if i == app.selected_index {
                Style::default()
                    .fg(Color::Yellow)
                    .add_modifier(Modifier::BOLD)
            } else {
                Style::default()
            };
            ListItem::new(Line::from(vec![
                Span::styled(
                    format!("{score:.2}  "),
                    Style::default().fg(Color::DarkGray),
                ),
                Span::styled(title, style),
            ]))
        })
        .collect();

    let list = List::new(items).block(
        Block::default()
            .borders(Borders::ALL)
            .title(format!(" Results ({}) ", app.search_results.len())),
    );
    frame.render_widget(list, chunks[1]);
}

fn render_tags(frame: &mut Frame, app: &App, area: ratatui::layout::Rect) {
    let items: Vec<ListItem> = app
        .tag_list
        .iter()
        .enumerate()
        .map(|(i, tag)| {
            let style = if i == app.selected_index {
                Style::default()
                    .fg(Color::Green)
                    .add_modifier(Modifier::BOLD)
            } else {
                Style::default().fg(Color::Green)
            };
            ListItem::new(Span::styled(format!("  #{tag}"), style))
        })
        .collect();

    let list = List::new(items).block(
        Block::default()
            .borders(Borders::ALL)
            .title(format!(" Tags ({}) ", app.tag_list.len())),
    );
    frame.render_widget(list, area);
}

fn panel_name(panel: Panel) -> &'static str {
    match panel {
        Panel::NoteList => "NOTES",
        Panel::NoteView => "VIEW",
        Panel::Search => "SEARCH",
        Panel::Tags => "TAGS",
    }
}
